/**
 * User validation — pure functions for validating user-related inputs.
 *
 * These validators contain no side effects and no database calls.
 * Services look up entities and pass them to these validators.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken by another user.
 * Throws if `existingUserWithEmail` is defined.
 */
export function validateEmailNotTaken(
  email: string,
  existingUserWithEmail: User | undefined,
): void {
  if (existingUserWithEmail) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that a user exists.
 * Throws if `user` is undefined.
 */
export function validateUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an email is not taken during an update.
 * Only checks if the email is actually being changed.
 * Throws if the new email is already in use by another user.
 */
export function validateEmailNotTakenForUpdate(
  newEmail: string | undefined,
  currentEmail: string,
  existingUserWithEmail: User | undefined,
): void {
  if (newEmail && newEmail !== currentEmail && existingUserWithEmail) {
    throw new Error(`Email ${newEmail} is already in use`);
  }
}

/**
 * Order validation — pure functions for validating order-related inputs.
 *
 * These validators contain no side effects and no database calls.
 * Services look up entities and pass them to these validators.
 */

import type { Order, OrderItem, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that a user exists (used before creating an order).
 * Throws if `user` is undefined.
 */
export function validateUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an order has at least one item.
 * Throws if items array is empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that an order exists.
 * Throws if `order` is undefined.
 */
export function validateOrderExists(
  order: Order | undefined,
  orderId: string,
): asserts order is Order {
  if (!order) {
    throw new Error(`Order not found: ${orderId}`);
  }
}

/**
 * Check whether a status transition is allowed.
 * Returns true if the transition from `from` to `to` is valid.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed.
 * Throws if the transition is invalid.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

