import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateUserExists,
  validateEmailNotTakenForUpdate,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('user.validator', () => {
  describe('validateEmailNotTaken', () => {
    it('should pass when no existing user has the email', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailNotTaken('taken@example.com', existing)).toThrow(
        'User with email taken@example.com already exists',
      );
    });
  });

  describe('validateUserExists', () => {
    it('should pass when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });

    it('should narrow type after assertion', () => {
      const user: User | undefined = makeUser();
      validateUserExists(user, 'user-0001');
      // After assertion, user is narrowed to User (not undefined)
      expect(user.name).toBe('Alice');
    });
  });

  describe('validateEmailNotTakenForUpdate', () => {
    it('should pass when email is not being changed', () => {
      expect(() =>
        validateEmailNotTakenForUpdate(undefined, 'alice@example.com', undefined),
      ).not.toThrow();
    });

    it('should pass when new email is same as current', () => {
      expect(() =>
        validateEmailNotTakenForUpdate('alice@example.com', 'alice@example.com', undefined),
      ).not.toThrow();
    });

    it('should pass when new email is different and not taken', () => {
      expect(() =>
        validateEmailNotTakenForUpdate('new@example.com', 'alice@example.com', undefined),
      ).not.toThrow();
    });

    it('should throw when new email is different and already taken', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() =>
        validateEmailNotTakenForUpdate('taken@example.com', 'alice@example.com', existing),
      ).toThrow('Email taken@example.com is already in use');
    });

    it('should pass when new email equals current even if existing user found', () => {
      // Edge case: findByEmail returns the same user (email unchanged)
      const existing = makeUser({ email: 'alice@example.com' });
      expect(() =>
        validateEmailNotTakenForUpdate('alice@example.com', 'alice@example.com', existing),
      ).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateOrderItems,
  validateOrderExists,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { User } from '../../src/models/user.js';
import type { Order, OrderItem, OrderStatus } from '../../src/models/order.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-0001',
    userId: 'user-0001',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('order.validator', () => {
  describe('validateUserExists', () => {
    it('should pass when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateOrderItems', () => {
    it('should pass when items array has elements', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should pass with multiple items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderItems([])).toThrow('Order must have at least one item');
    });
  });

  describe('validateOrderExists', () => {
    it('should pass when order exists', () => {
      const order = makeOrder();
      expect(() => validateOrderExists(order, 'order-0001')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-9999')).toThrow(
        'Order not found: order-9999',
      );
    });

    it('should narrow type after assertion', () => {
      const order: Order | undefined = makeOrder();
      validateOrderExists(order, 'order-0001');
      expect(order.status).toBe('pending');
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('delivered', status)).toBe(false);
      }
    });

    it('should reject cancelled -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('cancelled', status)).toBe(false);
      }
    });

    it('should reject shipped -> confirmed', () => {
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should pass for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('delivered', 'confirmed')).toThrow(
        'Invalid status transition: delivered -> confirmed',
      );
      expect(() => validateStatusTransition('cancelled', 'pending')).toThrow(
        'Invalid status transition: cancelled -> pending',
      );
    });
  });
});

